<script>
document.addEventListener("DOMContentLoaded", function() {
    var userInfo = document.getElementById("user-info");
    var dropdown = document.getElementById("user-dropdown");

    // Afficher le menu quand la souris entre sur user-info
    userInfo.addEventListener("mouseenter", function() {
        dropdown.style.display = "block"; // S'assurer qu'il est visible pour l'animation
        setTimeout(() => {
            dropdown.style.opacity = "1";
            dropdown.style.visibility = "visible";
        }, 10); // Petit d�lai pour activer l'animation
    });

    // Masquer le menu si la souris quitte user-info et user-dropdown
    function hideDropdown() {
        dropdown.style.opacity = "0";
        dropdown.style.visibility = "hidden";
        setTimeout(() => {
            dropdown.style.display = "none"; // Masquer apr�s l'animation
        }, 200); // Temps correspondant � la transition CSS
    }

    userInfo.addEventListener("mouseleave", function() {
        setTimeout(() => {
            if (!dropdown.matches(':hover')) {
                hideDropdown();
            }
        }, 200);
    });

    dropdown.addEventListener("mouseleave", function() {
        hideDropdown();
    });

    // Ajouter un gestionnaire pour le clic sur un �l�ment du menu
    var menuItems = dropdown.querySelectorAll("a");
    menuItems.forEach(function(item) {
        item.addEventListener("click", function() {
            // Supprimer la classe 'selected' de tous les �l�ments
            menuItems.forEach(function(menuItem) {
                menuItem.classList.remove("selected");
            });
            // Ajouter la classe 'selected' � l'�l�ment cliqu�
            item.classList.add("selected");
        });
    });
});
</script>
